    gap: var(--s-4);
  }
}

.shell-footer__copyright {
  margin: 0;
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  color: var(--fg-faint);
}

.shell-footer__links {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  color: var(--fg-faint);
}

.shell-footer__sep {
  color: var(--fg-faint);
  user-select: none;
}

